async function sendMessage() {
    const inputElement = document.getElementById('user-input');
    const chatContainer = document.getElementById('chat-container');
    const apiKey = localStorage.getItem('aura_api_key');
    const systemPrompt = localStorage.getItem('aura_system_prompt');
    const text = inputElement.value.trim();

    if (!text) return;
    if (!apiKey) {
        alert("Add your API Key first!");
        toggleSidebar();
        return;
    }

    appendMessage('user', text);
    inputElement.value = '';

    const typingId = appendTypingIndicator();
    chatContainer.scrollTop = chatContainer.scrollHeight;

    try {
        const contents = [...chatHistory];
        contents.push({ role: "user", parts: [{ text: text }] });

        const requestBody = {
            contents: contents,
            generationConfig: { temperature: 0.9, maxOutputTokens: 2048 }
        };

        if (systemPrompt) {
            requestBody.system_instruction = { parts: { text: systemPrompt } };
        }

        // Wait 2 seconds before kicking off Video A
        setTimeout(() => {
            if (vidA.paused && vidB.paused) {
                vidA.play().catch(e => console.log("User interaction required for video"));
            }
        }, 2000);

        const response = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/${modelName}:generateContent?key=${apiKey}`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(requestBody)
        });

        const data = await response.json();

        if (data.candidates && data.candidates[0].content) {
            const aiResponse = data.candidates[0].content.parts[0].text;

            // Helper to gate the response until B has played for 5s
            const checkAndDisplay = () => {
                const now = Date.now();
                const elapsedB = bStartedAt > 0 ? now - bStartedAt : 0;

                if (bStartedAt > 0 && elapsedB >= 5000) {
                    removeTypingIndicator(typingId);
                    appendMessage('model', aiResponse);
                    chatHistory.push({ role: "user", parts: [{ text: text }] });
                    chatHistory.push({ role: "model", parts: [{ text: aiResponse }] });
                    chatContainer.scrollTop = chatContainer.scrollHeight;
                } else {
                    // Keep checking every 100ms until the 5s requirement is met
                    setTimeout(checkAndDisplay, 100);
                }
            };

            checkAndDisplay();
        } else {
            throw new Error(data.error?.message || "Check API key.");
        }

    } catch (error) {
        removeTypingIndicator(typingId);
        appendMessage('ai', "Error: " + error.message);
    }

    chatContainer.scrollTop = chatContainer.scrollHeight;
}

